import React, { useState } from 'react';
import axios from 'axios';
import Dropzone from 'react-dropzone';
import './App.css';

function App() {
  const [file, setFile] = useState(null);
  const [targetColumn, setTargetColumn] = useState('diagnosis');
  const [dropColumns, setDropColumns] = useState('id');
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const onDrop = (acceptedFiles) => {
    setFile(acceptedFiles[0]);
    setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!file) {
      setError('Please select a CSV file');
      return;
    }

    setLoading(true);
    setError('');
    setResults(null);

    const formData = new FormData();
    formData.append('file', file);
    formData.append('targetColumn', targetColumn);
    formData.append('dropColumns', dropColumns);

    try {
      const response = await axios.post('http://localhost:5000/predict', formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      });
      setResults(response.data.results);
    } catch (err) {
      setError(err.response?.data?.error || 'Network Error: Could not connect to the server');
    } finally {
      setLoading(false);
    }
  };

  const parseResults = (resultsText) => {
    if (!resultsText) return { accuracies: [], bestModel: '', bestAccuracy: 0 };

    const lines = resultsText.split('\n');
    const accuracies = [];
    let bestModel = '';
    let bestAccuracy = 0;

    lines.forEach((line) => {
      line = line.trim();
      if (line.includes('Accuracy:') && !line.includes('Best Model:')) {
        const [namePart, accuracyPart] = line.split(' Accuracy: ');
        const name = namePart.trim();
        const accuracy = parseFloat(accuracyPart);
        if (!isNaN(accuracy)) {
          accuracies.push({ name, accuracy });
        }
      } else if (line.includes('Error:') && !line.includes('Best Model:')) {
        const [namePart, errorPart] = line.split(' Error: ');
        const name = namePart.trim();
        accuracies.push({ name, accuracy: 'Error', error: errorPart });
      } else if (line.startsWith('Best Model:')) {
        const parts = line.replace('Best Model:', '').split(' with Accuracy: ');
        bestModel = parts[0].trim();
        bestAccuracy = parseFloat(parts[1]);
      }
    });

    // Fallback to calculate best model if not explicitly provided
    if (!bestModel && accuracies.length > 0) {
      const validAccuracies = accuracies.filter(a => a.accuracy !== 'Error');
      if (validAccuracies.length > 0) {
        const best = validAccuracies.reduce((prev, curr) =>
          curr.accuracy > prev.accuracy ? curr : prev
        );
        bestModel = best.name;
        bestAccuracy = best.accuracy;
      }
    }

    return { accuracies, bestModel, bestAccuracy };
  };

  const { accuracies, bestModel, bestAccuracy } = parseResults(results);

  return (
    <div className="min-h-screen bg-gray-100 p-4 font-sans">
      <div className="max-w-4xl mx-auto">
        <header className="bg-white rounded-t-lg shadow-md p-6 border-b border-gray-200">
          <h1 className="text-3xl font-bold text-gray-800">Machine Learning Classifier</h1>
          <p className="mt-2 text-gray-600">Upload a CSV file to compare multiple ML models</p>
        </header>

        <main className="bg-white rounded-b-lg shadow-md p-6">
          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Dataset</label>
              <Dropzone
                onDrop={onDrop}
                accept={{ 'text/csv': ['.csv'] }}
                multiple={false}
              >
                {({ getRootProps, getInputProps }) => (
                  <div 
                    {...getRootProps()} 
                    className={`border-2 border-dashed rounded-md p-6 text-center cursor-pointer transition-all ${
                      file ? 'border-green-400 bg-green-50' : 'border-gray-300 bg-gray-50 hover:bg-gray-100'
                    }`}
                  >
                    <input {...getInputProps()} />
                    {file ? (
                      <>
                        <svg className="w-12 h-12 mx-auto text-green-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"></path>
                        </svg>
                        <p className="mt-2 text-sm font-medium text-gray-900">{file.name}</p>
                        <p className="text-xs text-gray-500">Click or drag to replace</p>
                      </>
                    ) : (
                      <>
                        <svg className="w-12 h-12 mx-auto text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path>
                        </svg>
                        <p className="mt-2 text-sm font-medium text-gray-900">Drop CSV file here</p>
                        <p className="text-xs text-gray-500">or click to browse files</p>
                      </>
                    )}
                  </div>
                )}
              </Dropzone>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Target Column</label>
                <input
                  type="text"
                  value={targetColumn}
                  onChange={(e) => setTargetColumn(e.target.value)}
                  placeholder="e.g., diagnosis"
                  className="w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Columns to Drop (comma-separated)
                </label>
                <input
                  type="text"
                  value={dropColumns}
                  onChange={(e) => setDropColumns(e.target.value)}
                  placeholder="e.g., id"
                  className="w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                />
              </div>
            </div>

            <div>
              <button
                type="submit"
                disabled={loading}
                className="w-full md:w-auto px-6 py-3 bg-blue-600 text-white font-medium rounded-md shadow-sm hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                {loading ? (
                  <span className="flex items-center justify-center">
                    <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-white" fill="none" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    Processing...
                  </span>
                ) : (
                  'Run Models'
                )}
              </button>
            </div>

            {error && (
              <div className="p-4 bg-red-50 border-l-4 border-red-500 rounded-md">
                <div className="flex">
                  <div className="flex-shrink-0">
                    <svg className="h-5 w-5 text-red-400" viewBox="0 0 20 20" fill="currentColor">
                      <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
                    </svg>
                  </div>
                  <div className="ml-3">
                    <p className="text-sm text-red-700">{error}</p>
                  </div>
                </div>
              </div>
            )}
          </form>

          {results && (
            <div className="mt-8 border-t border-gray-200 pt-6">
              <h2 className="text-xl font-semibold text-gray-800 mb-4">Model Performance</h2>
              <div className="overflow-x-auto bg-gray-50 rounded-lg border border-gray-200">
                <table className="min-w-full divide-y divide-gray-200">
                  <thead className="bg-gray-100">
                    <tr>
                      <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                        Model
                      </th>
                      <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                        Accuracy
                      </th>
                    </tr>
                  </thead>
                  <tbody className="bg-white divide-y divide-gray-200">
                    {accuracies.map((model, index) => (
                      <tr 
                        key={index}
                        className={model.name === bestModel ? 'bg-blue-50' : (index % 2 === 0 ? 'bg-white' : 'bg-gray-50')}
                      >
                        <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                          {model.name === bestModel && (
                            <span className="inline-flex items-center mr-2">
                              <svg className="h-5 w-5 text-blue-500" fill="currentColor" viewBox="0 0 20 20">
                                <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                              </svg>
                            </span>
                          )}
                          {model.name}
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                          {model.accuracy === 'Error' ? (
                            <span className="text-red-600">Error: {model.error}</span>
                          ) : (
                            <div className="flex items-center">
                              <div className="w-full bg-gray-200 rounded-full h-2.5 mr-2 max-w-xs">
                                <div 
                                  className="bg-blue-600 h-2.5 rounded-full" 
                                  style={{ width: `${model.accuracy * 100}%` }}
                                ></div>
                              </div>
                              <span className="font-medium">
                                {(model.accuracy * 100).toFixed(2)}%
                              </span>
                            </div>
                          )}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>

              {bestModel && (
                <div className="mt-6 p-4 bg-blue-50 border border-blue-200 rounded-lg">
                  <div className="flex items-center">
                    <div className="flex-shrink-0 bg-blue-100 rounded-full p-2">
                      <svg className="h-6 w-6 text-blue-600" fill="currentColor" viewBox="0 0 20 20">
                        <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                      </svg>
                    </div>
                    <div className="ml-4">
                      <h3 className="text-lg font-medium text-blue-800">Best Model: {bestModel}</h3>
                      <p className="text-blue-700">Accuracy: <span className="font-bold">{(bestAccuracy * 100).toFixed(2)}%</span></p>
                    </div>
                  </div>
                </div>
              )}
            </div>
          )}
        </main>
      </div>
    </div>
  );
}

export default App;
